namespace sv_5f882e149cc145a5a5ee6583f2292186.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped (per-circuit) service that holds the currently selected warehouse
/// and notifies subscribers when the selection changes.
/// </summary>
public class WarehouseStateService
{
    private static readonly List<WarehouseInfo> _warehouses =
    [
        new() { Id = "WH-001", Name = "Warehouse A – East" },
        new() { Id = "WH-002", Name = "Warehouse B – West" },
        new() { Id = "WH-003", Name = "Warehouse C – North" },
        new() { Id = "WH-004", Name = "Warehouse D – South" },
    ];

    public IReadOnlyList<WarehouseInfo> Warehouses => _warehouses;

    public string SelectedWarehouseId { get; private set; } = _warehouses[0].Id;

    public string SelectedWarehouseName =>
        _warehouses.First(w => w.Id == SelectedWarehouseId).Name;

    public event Func<Task>? OnChange;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (SelectedWarehouseId == warehouseId) return;
        SelectedWarehouseId = warehouseId;
        if (OnChange is not null)
            await OnChange.Invoke();
    }
}

namespace sv_5f882e149cc145a5a5ee6583f2292186.Services;

/// <summary>
/// Simulates a database query for low-stock items in a warehouse.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate async DB call with random result 0–15
        return Task.FromResult(_random.Next(0, 16));
    }
}

namespace sv_5f882e149cc145a5a5ee6583f2292186.Services;

/// <summary>
/// Scoped (per-circuit) pub/sub service that broadcasts alert count updates
/// to all subscribed components regardless of their position in the tree.
/// </summary>
public class AlertNotificationService
{
    public int CurrentCount { get; private set; }

    public event Func<int, Task>? OnAlertCountChanged;

    public async Task PublishCountAsync(int count)
    {
        CurrentCount = count;
        if (OnAlertCountChanged is not null)
            await OnAlertCountChanged.Invoke(count);
    }
}

