@page "/dashboard"
@rendermode InteractiveServer
@using sv_5f882e149cc145a5a5ee6583f2292186.Services
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService InventoryAlert
@inject AlertNotificationService AlertNotification
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Viewing: <strong>@WarehouseState.SelectedWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(_lowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(_lowStockCount > 0 ? "text-danger" : "text-success")">
                    @_lowStockCount
                </p>
                <p class="card-text text-muted">
                    items below minimum level
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="mt-3">
                    @if (_isPolling)
                    {
                        <span class="badge bg-success">● Active</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">● Stopped</span>
                    }
                </p>
                <p class="card-text text-muted small">Refreshes every 10 seconds</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Last Updated</h5>
                <p class="display-6">@(_lastUpdated?.ToString("HH:mm:ss") ?? "—")</p>
                <p class="card-text text-muted small">@WarehouseState.SelectedWarehouseId</p>
            </div>
        </div>
    </div>
</div>

@code {
    private int _lowStockCount;
    private bool _isPolling;
    private DateTime? _lastUpdated;
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertNotification.OnAlertCountChanged += OnAlertCountChanged;
        await FetchAndPublishAsync();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        _isPolling = true;
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            while (!token.IsCancellationRequested)
            {
                try
                {
                    await Task.Delay(TimeSpan.FromSeconds(10), token);
                    await InvokeAsync(async () =>
                    {
                        await FetchAndPublishAsync();
                        StateHasChanged();
                    });
                }
                catch (OperationCanceledException)
                {
                    break;
                }
            }
        }, token);
    }

    private async Task FetchAndPublishAsync()
    {
        _lowStockCount = await InventoryAlert.GetLowStockCountAsync(WarehouseState.SelectedWarehouseId);
        _lastUpdated = DateTime.Now;
        // Broadcast to all subscribers (including the sidebar badge)
        await AlertNotification.PublishCountAsync(_lowStockCount);
    }

    private async Task OnWarehouseChanged()
    {
        // Re-fetch immediately on warehouse switch
        await FetchAndPublishAsync();
        await InvokeAsync(StateHasChanged);
    }

    private async Task OnAlertCountChanged(int count)
    {
        _lowStockCount = count;
